import{_ as r,o as t,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"35. Higher Duties","description":"","frontmatter":{"title":"35. Higher Duties","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","wages","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/35-higher-duties.md","filePath":"ebas/nurses-midwives/allowances/35-higher-duties.md"}'),s={name:"ebas/nurses-midwives/allowances/35-higher-duties.md"};function o(n,e,h,l,d,g){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_35-higher-duties" tabindex="-1">35. Higher Duties <a class="header-anchor" href="#_35-higher-duties" aria-label="Permalink to &quot;35. Higher Duties&quot;">​</a></h1><p><strong>35.1</strong> General entitlement to higher duties payment – Registered Nurse or Midwife</p><p><strong>(a)</strong> Subject to clauses 35.2, 35.3, 35.4 and 35.5, a Registered Nurse or Midwife engaged on duties attracting a higher Level, grade or sub-grade than the Level, grade or sub-grade in which the Employee is ordinarily employed:</p><p><strong>(i)</strong> in any one shift for more than two hours will be paid for the full shift at the minimum rate for that higher Level, grade or sub-grade; or</p><p><strong>(ii)</strong> for two hours or less, only the time so worked will be paid for at that higher Level, grade or sub-grade.</p><p><strong>(b)</strong> Level for the purposes of this clause 0 means a role in which the weekly salary in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> for that role is higher than the Employee&#39;s normal role.</p><p><strong>35.2</strong> General entitlement to higher duties allowance – Enrolled Nurse</p><p><strong>(a)</strong> Where an Enrolled Nurse Employee is required to replace an ANUM In Charge of a high care residential aged care ward they will be paid the ANUM rate for that period.</p><p><strong>(b)</strong> During the shift the Enrolled Nurse must have access to a Registered Nurse.</p><p><strong>(c)</strong> In a high care residential aged care ward, an Enrolled Nurse can only be appointed to replace an ANUM as in charge where a Registered Nurse is not available to be rostered in charge.</p><p><strong>35.3</strong> Entitlement to higher duties payment for certain Deputy and Principal roles</p><p>A Deputy Director of Nursing, Deputy Principal Nurse Educator or Principal Nurse Educator will only receive higher duties payments when relieving an Employee in a higher Level, grade or sub-grade who is absent for a period in excess of five days. If that occurs the Employee will be paid at the minimum of that higher Level, grade or sub-grade for the entire period of relief.</p><p><strong>35.4</strong> Entitlement to higher duties payment for ANUM/AMUM acting as NUM/MUM</p><p>An ANUM or AMUM required to relieve a NUM or MUM who is absent for more than five days will be paid at the rate of pay for the Nurse Manager grade applicable to the substantive position (be it NM 2, NM 3 or NM 4) for the entire period of relief.</p><p><strong>35.5</strong> Entitlement to higher duties payment for Registered Nurse or Registered Midwife acting as ANUM/AMUM</p><p>Provided that <a href="/eba/ebas/nurses-midwives/classification-staffing/90-staffing-anum-amum-and-above.html">clause 90.2</a> (Associate Nurse/Midwife Unit Managers) is complied with, a Registered Nurse or Registered Midwife who relieves in an ANUM/AMUM position will be</p><p>paid at the minimum rate for that classification only where she/he is engaged for the full day or shift in that classification.</p><p><strong>35.6</strong> Entitlement to higher duties payment for Registered Nurse or Registered Midwife acting as NUM/MUM</p><p><strong>(a)</strong> An Employee who is not an ANUM or AMUM should only be in charge of a ward or unit in exceptional circumstances.</p><p><strong>(b)</strong> A Registered Nurse or Registered Midwife who is not an ANUM or AMUM, who is required to act in charge of a ward or unit during an off duty period of a NUM/MUM, will be paid at the Nurse Manager grade applicable to the substantive position (be it NM 2, NM 3 or NM 4) for the entire shift unless:</p><p><strong>(i)</strong> in the case of a 24 hour a day, seven day per week Ward or Unit that is compliant with subclause 90.2(a)(i);</p><p><strong>(ii)</strong> the ANUM/AMUM in whose place the Registered Nurse or Registered Midwife acts, is on any form of leave; or</p><p><strong>(iii)</strong> for a reasonable period where the vacancy arises directly from the termination of employment of an ANUM/AMUM while a replacement ANUM/AMUM is being recruited,</p><p>in which case a Registered Nurse or Registered Midwife will be paid at the minimum rate applicable to the ANUM/AMUM position which would normally be in charge on that shift.</p><p>Plain language terms: acting up, higher duties allowance, HDA.</p>',25)])])}const c=r(s,[["render",o]]);export{u as __pageData,c as default};
